#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e5+5;
const LL INF = 0x3f3f3f3f3f3f3f3f;
LL n,m,sum,St,Ed,dis[N];
LL dx[]={1,0,-1,0};
LL dy[]={0,1,0,-1};
bool a[205][205];queue<LL> q;
LL tot=1,head[N],to[N],wei[N],nxt[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int Node(int x,int y){return (x-1)*m+y;}
void Add_edge(int x,int y,LL z){
    ++tot,to[tot]=y,wei[tot]=z;
    nxt[tot]=head[x],head[x]=tot;
    ++tot,to[tot]=x,wei[tot]=0;
    nxt[tot]=head[y],head[y]=tot;return;
}
bool BFS_Canit(){
    for(int i=1;i<=Ed;i++)dis[i]=0;
    while(!q.empty())q.pop();
    dis[St]=1,q.push(St);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=head[u];i;i=nxt[i]){
            LL v=to[i],w=wei[i];
            if(!w||dis[v])continue;
            dis[v]=dis[u]+1;
            if(v==Ed)return 1;q.push(v);
        }
    }return 0;
}
LL DFS_Cntflow(int u,LL flow){
    if(u==Ed)return flow;LL now=flow;
    for(int i=head[u];i;i=nxt[i]){
        if(now<=0)break;
        LL v=to[i],w=wei[i];
        if(!w||dis[v]!=dis[u]+1)continue;
        LL tmp=DFS_Cntflow(v,min(now,w));
        if(!tmp)dis[v]=0;
        else wei[i]-=tmp,wei[i^1]+=tmp,now-=tmp;
    }return flow-now;
}
LL Sol_Dinic(){
    LL res=0,flow=0;
    while(BFS_Canit())
        while(flow=DFS_Cntflow(St,INF))res+=flow;
    return res;
}
int main(){
    n=read(),m=read();
    St=n*m+1,Ed=St+1;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            LL w=read();sum+=w;
            if((i+j)%2==1)Add_edge(St,Node(i,j),w);
            else Add_edge(Node(i,j),Ed,w);
        }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            if((i+j)%2==0)continue;
            for(int k=0;k<4;k++){
                int x=i+dx[k],y=j+dy[k];
                if(x>=1&&x<=n&&y>=1&&y<=m)
                    Add_edge(Node(i,j),Node(x,y),INF);
            }
        }
    cout<<sum-Sol_Dinic()<<"\n";
    return 0;
}
